mapper.select:

SELECT *
FROM 
	SYS_ROLE			


ENABLED_FLAG=1			

	AND ID=#{id}


	AND UPPER(NAME) like UPPER(CONCAT(CONCAT('%', #{name}), '%'))


	AND PARENT_ID=#{parentId}


	AND UPPER(DESCRIPTION) like UPPER(CONCAT(CONCAT('%', #{description}), '%'))


	AND UPPER(STATUS) like UPPER(CONCAT(CONCAT('%', #{status}), '%'))


	AND ENABLED_FLAG=#{enabledFlag}


	AND CREATED_BY=#{createdBy}


	AND CREATION_DATE=#{creationDate}


	AND LAST_UPDATED_BY=#{lastUpdatedBy}


	AND LAST_UPDATE_DATE=#{lastUpdateDate}


ORDER BY ID


SELECT 
	*
FROM 
	SYS_ROLE			


ENABLED_FLAG=1			

	AND ID=#{bo.id}


	AND UPPER(NAME) like UPPER(CONCAT(CONCAT('%', #{bo.name}), '%'))


	AND PARENT_ID=#{bo.parentId}


	AND UPPER(DESCRIPTION) like UPPER(CONCAT(CONCAT('%', #{bo.description}), '%'))


	AND UPPER(STATUS) like UPPER(CONCAT(CONCAT('%', #{bo.status}), '%'))


	AND upper(STATUS) IN	

		'${status}'



	AND ENABLED_FLAG=#{bo.enabledFlag}


	AND CREATED_BY=#{bo.createdBy}


	AND CREATION_DATE=#{bo.creationDate}


	AND LAST_UPDATED_BY=#{bo.lastUpdatedBy}


	AND LAST_UPDATE_DATE=#{bo.lastUpdateDate}


ORDER BY ${page.sortFieldName} DESC
